{"content":"     1	import SwiftUI
     2	import LoomCore
     3	import LoomDesign
     4	import LoomUI
     5	
     6	@main
     7	struct LoomApp: App {
     8	
     9	    @State private var app = AppModel()
    10	    @State private var coordinator: LibraryCoordinator?
    11	    @State private var favorites = FavoritesCoordinator()
    12	    @State private var exporter: ExportCoordinator?
    13	    @State private var handSense: HandSenseCoordinator?
    14	
    15	    var body: some Scene {
    16	        WindowGroup {
    17	            RootScene()
    18	                .environment(app)
    19	                .environment(\.loomFavorites, favorites)
    20	                .environment(\.locale, app.languagePreference.locale ?? Locale.autoupdatingCurrent)
    21	                .frame(minWidth: 960, minHeight: 640)
    22	                .preferredColorScheme(.light)
    23	                .background(Palette.canvas.ignoresSafeArea())
    24	                .id(app.languagePreference.rawValue)
    25	                .task {
    26	                    if coordinator == nil {
    27	                        let c = LibraryCoordinator(app: app, favorites: favorites)
    28	                        coordinator = c
    29	                        c.bootstrap()
    30	                    }
    31	                    if exporter == nil {
    32	                        exporter = ExportCoordinator(app: app)
    33	                    }
    34	                    if handSense == nil {
    35	                        let h = HandSenseCoordinator(app: app)
    36	                        handSense = h
    37	                        // Auto-resume capture if the user had it on
    38	                        // previously and camera is still authorized —
    39	                        // never cold-prompts for camera at launch.
    40	                        h.bootstrap()
    41	                    }
    42	                }
    43	        }
    44	        .windowStyle(.hiddenTitleBar)
    45	        .windowResizability(.contentMinSize)
    46	        .commands {
    47	            AppCommands(app: app, favorites: favorites)
    48	        }
    49	
    50	        Settings {
    51	            SettingsView()
    52	                .environment(app)
    53	                .environment(\.locale, app.languagePreference.locale ?? Locale.autoupdatingCurrent)
    54	                .preferredColorScheme(.light)
    55	                .id(app.languagePreference.rawValue)
    56	        }
    57	    }
    58	}
    59	
    60	/// Environment key so any view in LoomUI can reach the FavoritesCoordinator
    61	/// without the top-level executable target needing to vend it down as a
    62	/// prop chain. The coordinator is @MainActor-isolated; access site stays
    63	/// on the main actor.
    64	private struct LoomFavoritesKey: EnvironmentKey {
    65	    static let defaultValue: FavoritesCoordinator? = nil
    66	}
    67	
    68	extension EnvironmentValues {
    69	    var loomFavorites: FavoritesCoordinator? {
    70	        get { self[LoomFavoritesKey.self] }
    71	        set { self[LoomFavoritesKey.self] = newValue }
    72	    }
    73	}
