{"content":"     1	import SwiftUI
     2	import AppKit
     3	import LoomCore
     4	import LoomDesign
     5	
     6	/// The app's Settings surface.
     7	///
     8	/// Opened via ⌘, (standard macOS shortcut) or the gear button on the wall
     9	/// (top-right). Four tabs:
    10	///
    11	///   • General — language override
    12	///   • Library — current source, change, clear
    13	///   • Privacy — offline / on-device guarantees, clear-index action
    14	///   • About   — version, license, GitHub
    15	///
    16	/// Styling follows the paper-canvas aesthetic: surface-on-canvas cards,
    17	/// warm charcoal ink, terracotta accents. Kept deliberately compact
    18	/// (~520×380) so the window feels in-product, not like a generic
    19	/// Preferences panel.
    20	struct SettingsView: View {
    21	    @Environment(AppModel.self) private var app
    22	
    23	    var body: some View {
    24	        TabView {
    25	            GeneralSettings()
    26	                .tabItem { Label("General", systemImage: "slider.horizontal.3") }
    27	
    28	            LibrarySettings()
    29	                .tabItem { Label("Library", systemImage: "folder") }
    30	
    31	            PrivacySettings()
    32	                .tabItem { Label("Privacy", systemImage: "lock.shield") }
    33	
    34	            AboutSettings()
    35	                .tabItem { Label("About", systemImage: "info.circle") }
    36	        }
    37	        .padding(LoomSpacing.lg)
    38	        .frame(width: 520, height: 420)
    39	        .background(Palette.canvas)
    40	    }
    41	}
    42	
    43	// MARK: — General
    44	
    45	private struct GeneralSettings: View {
    46	    @Environment(AppModel.self) private var app
    47	
    48	    var body: some View {
    49	        SettingsScroll {
    50	            SettingsSection(title: "Language") {
    51	                Picker("", selection: Binding(
    52	                    get: { app.languagePreference },
    53	                    set: { app.setLanguage($0) }
    54	                )) {
    55	                    ForEach(LanguagePreference.allCases, id: \.self) { pref in
    56	                        Text(pref.displayName).tag(pref)
    57	                    }
    58	                }
    59	                .pickerStyle(.segmented)
    60	                .labelsHidden()
    61	            }
    62	
    63	            SettingsSection(title: "Wall density") {
    64	                VStack(alignment: .leading, spacing: LoomSpacing.sm) {
    65	                    Picker("", selection: Binding(
    66	                        get: { app.density },
    67	                        set: { newValue in
    68	                            app.setDensity(newValue)
    69	                            // Re-shuffle so the change is immediately
    70	                            // visible — density only affects new
    71	                            // compositions, not the current tile frames.
    72	                            NotificationCenter.default.post(
    73	                                name: .loomShuffle, object: nil
    74	                            )
    75	                        }
    76	                    )) {
    77	                        ForEach(WallDensity.allCases, id: \.self) { d in
    78	                            Text(d.displayName).tag(d)
    79	                        }
    80	                    }
    81	                    .pickerStyle(.segmented)
    82	                    .labelsHidden()
    83	                    Text("Roomy shows fewer, larger photos · Dense packs more per wall. Hero styles (Editorial, Exhibit) stay fixed.")
    84	                        .font(LoomType.caption)
    85	                        .foregroundStyle(Palette.inkFaint)
    86	                        .lineLimit(nil)
    87	                        .fixedSize(horizontal: false, vertical: true)
    88	                }
    89	            }
    90	
    91	            SettingsSection(title: "Quality filter") {
    92	                VStack(alignment: .leading, spacing: LoomSpacing.sm) {
    93	                    Toggle(isOn: Binding(
    94	                        get: { app.filterQuality },
    95	                        set: { newValue in
    96	                            app.setFilterQuality(newValue)
    97	                            NotificationCenter.default.post(
    98	                                name: .loomShuffle, object: nil
    99	                            )
   100	                        }
   101	                    )) {
   102	                        Text("Filter low-quality photos")
   103	                            .font(LoomType.body)
   104	                            .foregroundStyle(Palette.ink)
   105	                    }
   106	                    Text("Skip blurry, overexposed, and very small photos when composing the wall. Pinned photos are always shown.")
   107	                        .font(LoomType.caption)
   108	                        .foregroundStyle(Palette.inkFaint)
   109	                        .lineLimit(nil)
   110	                        .fixedSize(horizontal: false, vertical: true)
   111	                }
   112	            }
   113	
   114	            SettingsSection(title: "Auto trim") {
   115	                VStack(alignment: .leading, spacing: LoomSpacing.sm) {
   116	                    Toggle(isOn: Binding(
   117	                        get: { app.autoTrimEnabled },
   118	                        set: { newValue in
   119	                            app.setAutoTrimEnabled(newValue)
   120	                            NotificationCenter.default.post(
   121	                                name: .loomShuffle, object: nil
   122	                            )
   123	                        }
   124	                    )) {
   125	                        Text("Crop black / white borders")
   126	                            .font(LoomType.body)
   127	                            .foregroundStyle(Palette.ink)
   128	                    }
   129	                    Text("Automatically zoom past near-black or near-white letterbox edges so the photo fills its tile.")
   130	                        .font(LoomType.caption)
   131	                        .foregroundStyle(Palette.inkFaint)
   132	                        .lineLimit(nil)
   133	                        .fixedSize(horizontal: false, vertical: true)
   134	                }
   135	            }
   136	
   137	            SettingsSection(title: "Gestures") {
   138	                VStack(alignment: .leading, spacing: LoomSpacing.sm) {
   139	                    Toggle(isOn: Binding(
   140	                        get: { app.handSenseEnabled },
   141	                        set: { newValue in
   142	                            NotificationCenter.default.post(
   143	                                name: .loomHandSenseToggle, object: newValue
   144	                            )
   145	                        }
   146	                    )) {
   147	                        Text("Control the wall with hand gestures")
   148	                            .font(LoomType.body)
   149	                            .foregroundStyle(Palette.ink)
   150	                    }
   151	                    Text("Open your palm to spread · make a fist to gather · shake to shuffle. Camera access required. Video is processed in memory and never recorded.")
   152	                        .font(LoomType.caption)
   153	                        .foregroundStyle(Palette.inkFaint)
   154	                        .lineLimit(nil)
   155	                        .fixedSize(horizontal: false, vertical: true)
   156	                }
   157	            }
   158	
   159	            SettingsSection(title: "Keyboard") {
   160	                KeyboardCheatsheet()
   161	            }
   162	        }
   163	    }
   164	}
   165	
   166	private struct KeyboardCheatsheet: View {
   167	    // Tuples of (key, localized description key).
   168	    private let rows: [(String, String)] = [
   169	        ("␣",     "Shuffle"),
   170	        ("⌘1–⌘7", "Change style"),
   171	        ("⌘O",    "Pick Library…"),
   172	        ("⌘S",    "Save Wall as Favorite"),
   173	        ("⌘E",    "Export as PNG…"),
   174	        ("⌘⇧P",  "Export as PDF…"),
   175	        ("⌘⇧L",  "Clear Locks")
   176	    ]
   177	
   178	    var body: some View {
   179	        VStack(spacing: LoomSpacing.xs) {
   180	            ForEach(rows, id: \.0) { row in
   181	                HStack {
   182	                    Text(LocalizedStringKey(row.1))
   183	                        .font(LoomType.caption)
   184	                        .foregroundStyle(Palette.inkMuted)
   185	                    Spacer()
   186	                    Text(row.0)
   187	                        .font(LoomType.mono)
   188	                        .foregroundStyle(Palette.ink)
   189	                        .padding(.horizontal, LoomSpacing.sm)
   190	                        .padding(.vertical, 2)
   191	                        .background(
   192	                            RoundedRectangle(cornerRadius: 5, style: .continuous)
   193	                                .fill(Palette.surfaceElevated)
