{"content":"     1	import Foundation
     2	import SwiftUI
     3	
     4	/// How tightly photos are packed on the wall.
     5	///
     6	/// Expressed as a multiplier on the composer's baseline tile area: higher
     7	/// multipliers mean bigger tiles (fewer of them); lower means smaller
     8	/// (more of them). The user picks this in Settings; the composer reads it
     9	/// on every Shuffle and sizes the target count accordingly.
    10	///
    11	/// Style-specific caps still apply — Exhibit/Editorial are hero layouts
    12	/// with hardcoded 1+N tiles, and Minimal intentionally stays at 3–5. The
    13	/// density knob most visibly affects Tapestry, Gallery, Collage, Vintage.
    14	public enum WallDensity: String, CaseIterable, Sendable, Codable {
    15	    case roomy
    16	    case balanced
    17	    case dense
    18	
    19	    public var id: String { rawValue }
    20	
    21	    /// Multiplier applied to the composer's baseline tile area. >1 yields
    22	    /// bigger tiles (because area / baseline drops), <1 yields smaller.
    23	    public var tileAreaFactor: Double {
    24	        switch self {
    25	        case .roomy:    1.7
    26	        case .balanced: 1.0
    27	        case .dense:    0.55
    28	        }
    29	    }
    30	
    31	    public var displayName: LocalizedStringKey {
    32	        switch self {
    33	        case .roomy:    return "Roomy"
    34	        case .balanced: return "Balanced"
    35	        case .dense:    return "Dense"
    36	        }
    37	    }
    38	
    39	    // MARK: — Persistence
    40	
    41	    private static let storageKey = "loom.wallDensity"
    42	
    43	    public static var persisted: WallDensity {
    44	        get {
    45	            guard
    46	                let raw = UserDefaults.standard.string(forKey: storageKey),
    47	                let value = WallDensity(rawValue: raw)
    48	            else { return .balanced }
    49	            return value
    50	        }
    51	        set {
    52	            UserDefaults.standard.set(newValue.rawValue, forKey: storageKey)
    53	        }
    54	    }
    55	}
